import (
	"sort"
)

func solve(nums []int64) int64 {
	abs := make([]int64, len(nums))
	for i := 0; i < len(nums); i++ {
		if nums[i] < 0 {
			abs[i] = -nums[i]
		} else {
			abs[i] = nums[i]
		}
	}
	sort.Slice(abs, func(i, j int) bool { return abs[i] < abs[j] })
	var count int64
	n := len(abs)
	for i := 0; i < n-1; i++ {
		target := 2 * abs[i]
		left := i + 1
		right := n
		for left < right {
			mid := (left + right) / 2
			if abs[mid] <= target {
				left = mid + 1
			} else {
				right = mid
			}
		}
		count += int64(left - (i + 1))
	}
	return count
}
